/**
 * Reads public/ files and writes server/static.js with their contents
 * inlined as base64 buffers. Run before pkg so the files are bundled
 * as a script (not an asset), avoiding pkg's broken path handling for
 * project directories that contain spaces.
 */
const fs = require('fs');
const path = require('path');

const ROOT = path.join(__dirname, '..');
const PUBLIC_DIR = path.join(ROOT, 'public');
const OUTPUT = path.join(ROOT, 'server', 'static.js');

const MIME_TYPES = {
  '.html': 'text/html; charset=utf-8',
  '.js':   'application/javascript; charset=utf-8',
  '.css':  'text/css; charset=utf-8',
  '.png':  'image/png',
  '.jpg':  'image/jpeg',
  '.svg':  'image/svg+xml',
  '.ico':  'image/x-icon',
};

const files = fs.readdirSync(PUBLIC_DIR).filter(name => {
  const ext = path.extname(name);
  return ext && MIME_TYPES[ext];
});

const entries = files.map(name => {
  const content = fs.readFileSync(path.join(PUBLIC_DIR, name));
  const b64 = content.toString('base64');
  const mime = MIME_TYPES[path.extname(name)];
  return `  ${JSON.stringify(name)}: { mime: ${JSON.stringify(mime)}, data: Buffer.from(${JSON.stringify(b64)}, 'base64') }`;
});

const output = [
  '// AUTO-GENERATED by scripts/bundle-public.js — do not edit manually',
  `// Generated: ${new Date().toISOString()}`,
  'module.exports = {',
  entries.join(',\n'),
  '};',
  '',
].join('\n');

fs.writeFileSync(OUTPUT, output);
console.log(`Bundled ${files.length} public files into server/static.js (${(output.length / 1024).toFixed(1)} KB)`);
